svg.script:
// Perlin noise
class PerlinNoise {
  constructor(seed = Math.random() * 10000) {
    this.p = [];
    for (let i = 0; i < 256; i++) this.p[i] = i;
    let n = seed;
    for (let i = 255; i > 0; i--) {
      n = (n * 16807) % 2147483647;
      const j = n % (i + 1);
      [this.p[i], this.p[j]] = [this.p[j], this.p[i]];
    }
    this.p = this.p.concat(this.p);
  }
  fade(t) { return t * t * t * (t * (t * 6 - 15) + 10); }
  lerp(a, b, t) { return a + t * (b - a); }
  grad(hash, x) { return (hash & 1) === 0 ? x : -x; }
  noise1D(x) {
    const xi = Math.floor(x) & 255;
    const xf = x - Math.floor(x);
    const u = this.fade(xf);
    return this.lerp(this.grad(this.p[xi], xf), this.grad(this.p[xi + 1], xf - 1), u);
  }
}

// Key positions (center x, top y) in global coords
const keyPositions = [
  // Top row
  { x: 40.5, y: 78 }, { x: 55.5, y: 78 }, { x: 70.5, y: 78 }, { x: 85.5, y: 78 },
  { x: 100.5, y: 78 }, { x: 115.5, y: 78 }, { x: 130.5, y: 78 }, { x: 145.5, y: 78 }, { x: 160.5, y: 78 },
  // Middle row
  { x: 43.5, y: 89 }, { x: 58.5, y: 89 }, { x: 73.5, y: 89 }, { x: 88.5, y: 89 },
  { x: 103.5, y: 89 }, { x: 118.5, y: 89 }, { x: 133.5, y: 89 }, { x: 148.5, y: 89 },
  // Bottom row
  { x: 46.5, y: 100 }, { x: 61.5, y: 100 }, { x: 95, y: 100 }, // spacebar center
  { x: 128.5, y: 100 }, { x: 143.5, y: 100 }, { x: 158.5, y: 100 }
];

// Claudito transform offset
const clauditoX = 100;
const clauditoY = 18;

// Leg configs - each leg targets a subset of keys
const legs = [
  {
    el: document.getElementById('leg0'),
    noise: new PerlinNoise(1),
    anchorX: -16,  // local x
    anchorY: 32,   // local y
    width: 4,
    // Keys this leg can reach (left side)
    targetKeys: keyPositions.filter(k => k.x < 75),
    phase: 0,
    currentTarget: null,
    targetTime: 0
  },
  {
    el: document.getElementById('leg1'),
    noise: new PerlinNoise(2),
    anchorX: -10,
    anchorY: 32,
    width: 4,
    targetKeys: keyPositions.filter(k => k.x >= 55 && k.x < 100),
    phase: 0.7,
    currentTarget: null,
    targetTime: 0
  },
  {
    el: document.getElementById('leg2'),
    noise: new PerlinNoise(3),
    anchorX: 6,
    anchorY: 32,
    width: 4,
    targetKeys: keyPositions.filter(k => k.x >= 85 && k.x < 135),
    phase: 1.5,
    currentTarget: null,
    targetTime: 0
  },
  {
    el: document.getElementById('leg3'),
    noise: new PerlinNoise(4),
    anchorX: 12,
    anchorY: 32,
    width: 4,
    targetKeys: keyPositions.filter(k => k.x >= 115),
    phase: 2.2,
    currentTarget: null,
    targetTime: 0
  }
];

let time = 0;

function animate() {
  time += 0.016;

  legs.forEach(leg => {
    // Pick a new target key periodically based on noise
    const keySelectNoise = leg.noise.noise1D(time * 0.5 + leg.phase);
    const keyIndex = Math.floor((keySelectNoise * 0.5 + 0.5) * leg.targetKeys.length);
    const targetKey = leg.targetKeys[Math.min(keyIndex, leg.targetKeys.length - 1)];

    // Leg anchor in global coords
    const anchorGlobalX = clauditoX + leg.anchorX + leg.width / 2;
    const anchorGlobalY = clauditoY + leg.anchorY;

    // Vector from anchor to target key
    const dx = targetKey.x - anchorGlobalX;
    const dy = targetKey.y - anchorGlobalY;

    // Length needed to reach the key
    const length = Math.sqrt(dx * dx + dy * dy);

    // Angle to rotate leg (from vertical down)
    const angle = Math.atan2(dx, dy) * (180 / Math.PI);

    // Add noise-based wobble
    const wobble = leg.noise.noise1D(time * 3 + leg.phase) * 3;
    const stretchWobble = leg.noise.noise1D(time * 2 + leg.phase + 100) * 4;

    // Apply transforms
    leg.el.setAttribute('height', length + stretchWobble);

    // Rotate around the top-center of the leg
    const originX = leg.anchorX + leg.width / 2;
    const originY = leg.anchorY;
    leg.el.setAttribute('transform', `rotate(${angle + wobble}, ${originX}, ${originY})`);
  });

  requestAnimationFrame(animate);
}

animate();
